// ─── API helpers ─────────────────────────────────────────────────────
// Change this URL to your deployed backend URL
const API_URL = "";  // Same domain on Vercel — change to full URL if backend is separate

const api = {
  async post(endpoint, data) {
    try {
      const r = await fetch(`${API_URL}${endpoint}`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(data) });
      return await r.json();
    } catch { return { error: "Connection failed" }; }
  },
  async adminGet(endpoint, token) {
    try {
      const r = await fetch(`${API_URL}${endpoint}`, { headers: { "Authorization": `Bearer ${token}` } });
      return await r.json();
    } catch { return []; }
  },
  async adminDelete(endpoint, token) {
    try {
      const r = await fetch(`${API_URL}${endpoint}`, { method: "DELETE", headers: { "Authorization": `Bearer ${token}` } });
      return await r.json();
    } catch { return { error: "Failed" }; }
  },
  async adminPatch(endpoint, token, data) {
    try {
      const r = await fetch(`${API_URL}${endpoint}`, { method: "PATCH", headers: { "Content-Type": "application/json", "Authorization": `Bearer ${token}` }, body: JSON.stringify(data) });
      return await r.json();
    } catch { return { error: "Failed" }; }
  },
};

