// ─── Chatbot ─────────────────────────────────────────────────────────
const Chatbot = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [msgs, setMsgs] = useState([{ role: "assistant", content: "Greetings from Selela SA Africa. How can we assist you today?" }]);
  const [input, setInput] = useState("");
  const [typing, setTyping] = useState(false);
  const ref = useRef(null);
  useEffect(() => { if (ref.current) ref.current.scrollTop = ref.current.scrollHeight; }, [msgs, typing]);
  const send = async () => {
    if (!input.trim() || typing) return;
    const msg = input.trim(); setInput(""); setMsgs(p => [...p, { role: "user", content: msg }]); setTyping(true);
    try {
      const history = [...msgs, { role: "user", content: msg }].map(m => ({ role: m.role === "assistant" ? "assistant" : "user", content: m.content }));
      const r = await fetch("https://api.anthropic.com/v1/messages", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 1000, system: "You are the Senior Consultant for Selela SA Africa (Pty) Ltd. Expert in Construction, Industrial Engineering, Logistics, and Real Estate across Africa. Keep responses professional, concise (2-3 paragraphs max). Headquartered in 3482 Letlhabile Section, Ledig, South Africa. Contact: +27 82 729 3140, info@selelasaafrica.co.za.", messages: history }) });
      const d = await r.json(); const t = d.content?.map(c => c.text || "").join("") || "Connection error.";
      setMsgs(p => [...p, { role: "assistant", content: t }]);
    } catch { setMsgs(p => [...p, { role: "assistant", content: "System unavailable. Contact +27 82 729 3140." }]); }
    finally { setTyping(false); }
  };
  return (
    <div style={{ position: "fixed", bottom: 32, right: 32, zIndex: 100 }}>
      {isOpen && (
        <div style={{ marginBottom: 24, width: "min(92vw, 400px)", height: 520, background: "rgba(15,33,27,0.95)", backdropFilter: "blur(20px)", borderRadius: 32, display: "flex", flexDirection: "column", overflow: "hidden", boxShadow: "0 25px 50px rgba(0,0,0,0.5)", border: "1px solid rgba(190,242,100,0.1)", animation: "fadeUp 0.4s ease forwards" }}>
          <div style={{ padding: 18, background: C.forestMid, display: "flex", justifyContent: "space-between", alignItems: "center", borderBottom: "1px solid rgba(255,255,255,0.1)" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 12 }}><div style={{ width: 28, height: 28, borderRadius: "50%", background: "rgba(190,242,100,0.1)", display: "flex", alignItems: "center", justifyContent: "center" }}><div style={{ width: 8, height: 8, background: C.lime, borderRadius: "50%", animation: "pulse 2s infinite" }}/></div><h3 style={{ color: "white", fontWeight: 900, fontSize: 11, textTransform: "uppercase", letterSpacing: "0.1em" }}>Operations AI</h3></div>
            <button onClick={() => setIsOpen(false)} style={{ padding: 6, background: "none", border: "none", color: "#9ca3af", cursor: "pointer" }}><ChevronDown size={18}/></button>
          </div>
          <div ref={ref} style={{ flexGrow: 1, padding: 16, overflowY: "auto", display: "flex", flexDirection: "column", gap: 12 }}>
            {msgs.map((m, i) => <div key={i} style={{ display: "flex", justifyContent: m.role === "user" ? "flex-end" : "flex-start" }}><div style={{ maxWidth: "85%", padding: 12, borderRadius: 14, fontSize: 13, lineHeight: 1.6, ...(m.role === "user" ? { background: C.gold, color: "white", borderTopRightRadius: 0 } : { background: "rgba(255,255,255,0.05)", color: "#e5e7eb", border: "1px solid rgba(255,255,255,0.05)", borderTopLeftRadius: 0 }) }}>{m.content}</div></div>)}
            {typing && <div style={{ display: "flex" }}><div style={{ background: "rgba(255,255,255,0.05)", padding: 12, borderRadius: 14, borderTopLeftRadius: 0, border: "1px solid rgba(255,255,255,0.05)", display: "flex", gap: 4 }}>{[0,1,2].map(d=><div key={d} style={{ width: 5, height: 5, background: "#6b7280", borderRadius: "50%", animation: `bounce 1s ${d*0.2}s infinite` }}/>)}</div></div>}
          </div>
          <div style={{ padding: 16, borderTop: "1px solid rgba(255,255,255,0.1)", background: "rgba(7,18,14,0.5)" }}>
            <div style={{ position: "relative" }}>
              <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === "Enter" && send()} placeholder="Ask about our services..." style={{ width: "100%", boxSizing: "border-box", background: C.forestMid, border: "1px solid rgba(255,255,255,0.1)", borderRadius: 12, padding: "12px 44px 12px 14px", color: "white", fontSize: 13, outline: "none" }}/>
              <button onClick={send} disabled={!input.trim() || typing} style={{ position: "absolute", right: 6, top: 6, background: C.lime, color: C.forestDeep, padding: 7, borderRadius: 8, border: "none", cursor: "pointer", opacity: !input.trim() || typing ? 0.5 : 1 }}><SendHorizontal size={18}/></button>
            </div>
          </div>
        </div>
      )}
      <button onClick={() => setIsOpen(!isOpen)} style={{ width: 60, height: 60, borderRadius: 16, display: "flex", alignItems: "center", justifyContent: "center", border: "none", cursor: "pointer", boxShadow: "0 20px 40px rgba(0,0,0,0.3)", transition: "all 0.3s", background: isOpen ? C.forestMid : C.lime, color: isOpen ? C.lime : C.forestDeep, transform: isOpen ? "rotate(90deg)" : "none" }}>
        {isOpen ? <X size={26}/> : <MessageSquare size={26}/>}
      </button>
    </div>
  );
};

