// ─── Associates Page (Become an Associate form) ──────────────────────
const AssociatesPage = ({ go }) => {
  const [form, setForm] = useState({ name: "", company: "", email: "", phone: "", sector: "", experience: "", message: "" });
  const [success, setSuccess] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const set = (k, v) => setForm(p => ({ ...p, [k]: v }));

  const submit = async () => {
    if (!form.name || !form.company || !form.email || !form.sector) return;
    setSubmitting(true);
    const result = await api.post("/api/associates", form);
    if (result.success) { setSuccess(true); setForm({ name: "", company: "", email: "", phone: "", sector: "", experience: "", message: "" }); }
    setSubmitting(false);
  };

  return (
    <div style={{ maxWidth: 1280, margin: "0 auto", padding: 24, animation: "fadeUp 0.6s ease forwards" }}>
      <Tag>Join Our Network</Tag>
      <h1 style={{ fontSize: "clamp(28px, 4vw, 40px)", fontWeight: 700, color: "white", textTransform: "uppercase", marginBottom: 12 }}>Become an Associate</h1>
      <p style={{ color: "#9ca3af", fontSize: 16, marginBottom: 32, maxWidth: 600 }}>Partner with Selela SA Africa and join our growing network of industry leaders across the continent.</p>

      {success && <div style={{ marginBottom: 24 }}><SuccessMsg msg="Your associate application has been submitted. Our team will review and contact you shortly." onClose={() => setSuccess(false)} /></div>}

      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(340px, 1fr))", gap: 32 }}>
        <Glass style={{ borderRadius: 28, padding: "clamp(24px, 4vw, 40px)" }}>
          <h2 style={{ color: "white", fontWeight: 700, fontSize: 22, marginBottom: 8 }}>Application Form</h2>
          <p style={{ color: "#6b7280", fontSize: 13, marginBottom: 24 }}>Fields marked with * are required</p>
          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
              <InputField label="Full Name" value={form.name} onChange={v => set("name", v)} placeholder="John Doe" required />
              <InputField label="Company Name" value={form.company} onChange={v => set("company", v)} placeholder="Your Company" required />
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
              <InputField label="Email Address" value={form.email} onChange={v => set("email", v)} placeholder="john@company.com" type="email" required />
              <InputField label="Phone Number" value={form.phone} onChange={v => set("phone", v)} placeholder="+27 ..." type="tel" />
            </div>
            <InputField label="Industry Sector" value={form.sector} onChange={v => set("sector", v)} placeholder="e.g. Mining, Construction, Logistics" required />
            <InputField label="Years of Experience" value={form.experience} onChange={v => set("experience", v)} placeholder="e.g. 10+" />
            <InputField label="Why do you want to partner with us?" value={form.message} onChange={v => set("message", v)} placeholder="Tell us about your company and how we can collaborate..." textarea />
            <button onClick={submit} disabled={submitting || !form.name || !form.company || !form.email || !form.sector} style={{ padding: "16px 32px", background: "linear-gradient(135deg, #b89146, #bef264)", color: C.forestDeep, fontWeight: 700, borderRadius: 12, border: "none", cursor: "pointer", fontSize: 15, opacity: submitting || !form.name || !form.company || !form.email || !form.sector ? 0.5 : 1, transition: "opacity 0.3s", marginTop: 8 }}>
              {submitting ? "Submitting..." : "Submit Application"}
            </button>
          </div>
        </Glass>

        <div style={{ display: "flex", flexDirection: "column", gap: 24 }}>
          <div style={{ position: "relative", borderRadius: 28, overflow: "hidden", height: 220 }}><img src={IMAGES.consulting} alt="Partnership" style={{ width: "100%", height: "100%", objectFit: "cover" }}/><div style={{ position: "absolute", inset: 0, background: "linear-gradient(180deg, transparent 40%, rgba(7,18,14,0.9) 100%)" }}/><div style={{ position: "absolute", bottom: 24, left: 24 }}><h3 style={{ color: "white", fontWeight: 800, fontSize: 20 }}>Strategic Partnerships</h3><p style={{ color: "rgba(255,255,255,0.6)", fontSize: 13 }}>Growing together across Africa</p></div></div>
          <Glass style={{ borderRadius: 20, padding: 24 }}>
            <h3 style={{ color: "white", fontWeight: 700, fontSize: 16, marginBottom: 16 }}>Why Partner With Us?</h3>
            {["Access to mining, construction, and government procurement networks across North West and Gauteng", "Joint venture opportunities on CIDB-graded construction and mining support tenders", "Shared safety files, contractor packs, and OHS compliance documentation", "Level 1 B-BBEE partnership for enhanced procurement scoring and tender eligibility"].map((b, i) => (
              <div key={i} style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}><CheckCircle2 size={16} style={{ color: C.lime, flexShrink: 0 }}/><span style={{ color: "#9ca3af", fontSize: 14 }}>{b}</span></div>
            ))}
          </Glass>
        </div>
      </div>
    </div>
  );
};

