// ─── Admin Dashboard ─────────────────────────────────────────────────
const AdminPage = ({ go }) => {
  const [authed, setAuthed] = useState(false);
  const [token, setToken] = useState("");
  const [pass, setPass] = useState("");
  const [error, setError] = useState(false);
  const [tab, setTab] = useState("bookings");
  const [bookings, setBookings] = useState([]);
  const [contacts, setContacts] = useState([]);
  const [associates, setAssociates] = useState([]);
  const [loading, setLoading] = useState(false);

  const login = async () => {
    const result = await api.post("/api/admin/login", { password: pass });
    if (result.success) { setAuthed(true); setToken(result.token); setError(false); loadData(result.token); }
    else { setError(true); }
  };

  const loadData = async (tk) => {
    const t = tk || token;
    setLoading(true);
    const [b, c, a] = await Promise.all([
      api.adminGet("/api/admin/bookings", t),
      api.adminGet("/api/admin/contacts", t),
      api.adminGet("/api/admin/associates", t),
    ]);
    setBookings(Array.isArray(b) ? b : []); setContacts(Array.isArray(c) ? c : []); setAssociates(Array.isArray(a) ? a : []);
    setLoading(false);
  };

  const deleteEntry = async (type, id) => {
    await api.adminDelete(`/api/admin/${type}/${id}`, token);
    const setter = type === "bookings" ? setBookings : type === "contacts" ? setContacts : setAssociates;
    const data = type === "bookings" ? bookings : type === "contacts" ? contacts : associates;
    setter(data.filter(e => e.id !== id));
  };

  const formatDate = (d) => { try { return new Date(d).toLocaleDateString("en-ZA", { day: "numeric", month: "short", year: "numeric", hour: "2-digit", minute: "2-digit" }); } catch { return d; } };

  if (!authed) return (
    <div style={{ maxWidth: 440, margin: "80px auto", padding: 24, animation: "fadeUp 0.6s ease forwards" }}>
      <Glass style={{ borderRadius: 28, padding: 40, textAlign: "center" }}>
        <div style={{ width: 64, height: 64, borderRadius: "50%", background: "rgba(190,242,100,0.1)", display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 24px" }}><Lock size={28} style={{ color: C.lime }} /></div>
        <h2 style={{ color: "white", fontWeight: 700, fontSize: 24, marginBottom: 8 }}>Admin Login</h2>
        <p style={{ color: "#6b7280", fontSize: 14, marginBottom: 32 }}>Enter admin password to access the dashboard</p>
        {error && <div style={{ background: "rgba(239,68,68,0.1)", border: "1px solid rgba(239,68,68,0.3)", borderRadius: 12, padding: "10px 16px", marginBottom: 16, display: "flex", alignItems: "center", gap: 8 }}><AlertCircle size={16} style={{ color: "#ef4444" }}/><span style={{ color: "#fca5a5", fontSize: 13 }}>Incorrect password</span></div>}
        <input type="password" value={pass} onChange={e => { setPass(e.target.value); setError(false); }} onKeyDown={e => e.key === "Enter" && login()} placeholder="Enter password" style={{ width: "100%", boxSizing: "border-box", background: C.forestDeep, border: `1px solid ${error ? "rgba(239,68,68,0.3)" : "rgba(255,255,255,0.08)"}`, borderRadius: 12, padding: "14px 16px", color: "white", fontSize: 15, outline: "none", marginBottom: 16, textAlign: "center" }}/>
        <button onClick={login} style={{ width: "100%", padding: "14px", background: "linear-gradient(135deg, #b89146, #bef264)", color: C.forestDeep, fontWeight: 700, borderRadius: 12, border: "none", cursor: "pointer", fontSize: 15 }}>Login</button>
      </Glass>
    </div>
  );

  const tabs = [
    { id: "bookings", label: "Bookings", count: bookings.length, I: Calendar },
    { id: "contacts", label: "Inquiries", count: contacts.length, I: Mail },
    { id: "associates", label: "Applications", count: associates.length, I: Users },
  ];
  const currentData = tab === "bookings" ? bookings : tab === "contacts" ? contacts : associates;

  return (
    <div style={{ maxWidth: 1280, margin: "0 auto", padding: 24, animation: "fadeUp 0.6s ease forwards" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 32 }}>
        <div><Tag>Admin Dashboard</Tag><h1 style={{ fontSize: "clamp(24px, 3vw, 36px)", fontWeight: 700, color: "white", textTransform: "uppercase" }}>Control Panel</h1></div>
        <button onClick={() => { setAuthed(false); setPass(""); setToken(""); }} style={{ display: "flex", alignItems: "center", gap: 8, padding: "10px 20px", background: "rgba(239,68,68,0.1)", border: "1px solid rgba(239,68,68,0.2)", borderRadius: 12, color: "#fca5a5", cursor: "pointer", fontWeight: 600, fontSize: 13 }}><LogOut size={16}/> Logout</button>
      </div>

      <div style={{ display: "flex", gap: 12, marginBottom: 32, flexWrap: "wrap" }}>
        {tabs.map(t => (
          <button key={t.id} onClick={() => setTab(t.id)} style={{ display: "flex", alignItems: "center", gap: 8, padding: "12px 20px", borderRadius: 12, border: "none", cursor: "pointer", fontWeight: 700, fontSize: 13, transition: "all 0.3s", background: tab === t.id ? C.lime : "rgba(255,255,255,0.05)", color: tab === t.id ? C.forestDeep : "#9ca3af" }}>
            <t.I size={16}/> {t.label} <span style={{ background: tab === t.id ? "rgba(7,18,14,0.2)" : "rgba(255,255,255,0.1)", padding: "2px 8px", borderRadius: 8, fontSize: 11, fontWeight: 800 }}>{t.count}</span>
          </button>
        ))}
        <button onClick={loadData} style={{ marginLeft: "auto", padding: "12px 20px", borderRadius: 12, background: "rgba(255,255,255,0.05)", border: "none", color: "#9ca3af", cursor: "pointer", fontWeight: 700, fontSize: 13 }}>Refresh</button>
      </div>

      {loading ? (
        <Glass style={{ borderRadius: 20, padding: 40, textAlign: "center" }}><p style={{ color: "#9ca3af" }}>Loading...</p></Glass>
      ) : currentData.length === 0 ? (
        <Glass style={{ borderRadius: 20, padding: 60, textAlign: "center" }}>
          <div style={{ width: 56, height: 56, borderRadius: "50%", background: "rgba(255,255,255,0.05)", display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 16px" }}><FileText size={24} style={{ color: "#6b7280" }}/></div>
          <h3 style={{ color: "#6b7280", fontWeight: 700, fontSize: 18, marginBottom: 8 }}>No {tab} yet</h3>
          <p style={{ color: "#4b5563", fontSize: 14 }}>Submissions will appear here when users fill out forms on the site.</p>
        </Glass>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          {currentData.slice().reverse().map((entry, i) => (
            <Glass key={entry.id || i} style={{ borderRadius: 20, padding: 24, transition: "border-color 0.3s" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                <div>
                  <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
                    <User size={16} style={{ color: C.lime }}/><h3 style={{ color: "white", fontWeight: 700, fontSize: 16 }}>{entry.name}</h3>
                    {entry.status && <span style={{ padding: "2px 10px", borderRadius: 8, fontSize: 10, fontWeight: 700, textTransform: "uppercase", background: entry.status === "pending" ? "rgba(184,145,70,0.2)" : "rgba(190,242,100,0.2)", color: entry.status === "pending" ? C.gold : C.lime }}>{entry.status}</span>}
                  </div>
                  <p style={{ color: "#6b7280", fontSize: 12 }}>{formatDate(entry.date || entry.date_submitted)}</p>
                </div>
                <button onClick={() => deleteEntry(tab, entry.id)} style={{ padding: 8, background: "rgba(239,68,68,0.1)", border: "none", borderRadius: 8, color: "#ef4444", cursor: "pointer" }}><Trash2 size={16}/></button>
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))", gap: 12 }}>
                {entry.email && <div><span style={{ fontSize: 10, fontWeight: 700, color: "#6b7280", textTransform: "uppercase" }}>Email</span><p style={{ color: "#9ca3af", fontSize: 14 }}>{entry.email}</p></div>}
                {entry.phone && <div><span style={{ fontSize: 10, fontWeight: 700, color: "#6b7280", textTransform: "uppercase" }}>Phone</span><p style={{ color: "#9ca3af", fontSize: 14 }}>{entry.phone}</p></div>}
                {entry.company && <div><span style={{ fontSize: 10, fontWeight: 700, color: "#6b7280", textTransform: "uppercase" }}>Company</span><p style={{ color: "#9ca3af", fontSize: 14 }}>{entry.company}</p></div>}
                {entry.type && <div><span style={{ fontSize: 10, fontWeight: 700, color: "#6b7280", textTransform: "uppercase" }}>Service</span><p style={{ color: "#9ca3af", fontSize: 14 }}>{entry.type}</p></div>}
                {entry.preferred_date && <div><span style={{ fontSize: 10, fontWeight: 700, color: "#6b7280", textTransform: "uppercase" }}>Preferred Date</span><p style={{ color: "#9ca3af", fontSize: 14 }}>{entry.preferred_date} {entry.preferred_time || ""}</p></div>}
                {entry.sector && <div><span style={{ fontSize: 10, fontWeight: 700, color: "#6b7280", textTransform: "uppercase" }}>Sector</span><p style={{ color: "#9ca3af", fontSize: 14 }}>{entry.sector}</p></div>}
                {entry.experience && <div><span style={{ fontSize: 10, fontWeight: 700, color: "#6b7280", textTransform: "uppercase" }}>Experience</span><p style={{ color: "#9ca3af", fontSize: 14 }}>{entry.experience}</p></div>}
              </div>
              {(entry.message || entry.notes) && <div style={{ marginTop: 12, padding: 16, background: C.forestDeep, borderRadius: 12 }}><span style={{ fontSize: 10, fontWeight: 700, color: "#6b7280", textTransform: "uppercase" }}>Message</span><p style={{ color: "#9ca3af", fontSize: 14, lineHeight: 1.6, marginTop: 4 }}>{entry.message || entry.notes}</p></div>}
            </Glass>
          ))}
        </div>
      )}
    </div>
  );
};


